INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_MINING_RUSH', 'The Mining Rush', 4, 'Easy', True, 'Conquer 4 regions and achieve abundant Iron production. Keep food logistics running to support the booming miner population.', 'The discovery of a massive iron mine at the border has sparked a mining frenzy. The people are eager to expand and claim the riches of the frontier.', 50, 0.5, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_MERCHANTS_AMBITION', 'The Merchant''s Ambition', 5, 'Easy', False, 'Reach Prosperity 0.9 and accumulate 50,000 Gold within 50 turns. Administrative Strain kicks in earlier — starting from your 20th building.', 'Your kingdom sits on the Silk Road. Powerful merchants want you to transform this city into the world''s greatest trade hub.', 50, 0.55, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_SILENT_FAMINE', 'The Silent Famine', 7, 'Normal', False, 'Survive until Turn 50 with a population of at least 8,000. Enact emergency food laws before stability reaches zero.', 'A long drought has hit the land. Food reserves are nearly empty, and the people are eyeing the royal granary with growing anger.', 50, 0.4, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_ARCANE_UNREST', 'The Arcane Unrest', 8, 'Hard', False, 'Research 10 Technologies in the Tech Lab and maintain Stability above 70% until Turn 50. Manage the conflict between Mana growth and public loyalty.', 'Excessive use of Mana has caused weather anomalies across the realm. The Common Folk fear the mages, while the Arcane Circle demands more research funding.', 50, 0.7, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_DIVIDED_COUNCIL', 'The Divided Council', 9, 'Hard', False, 'Pass 5 High-Tier Laws (National Decrees) within 50 turns. PP is extremely scarce — every 10 buildings reduces Base PP by 1.', 'Parliament has fractured into two bitter rival factions. Bureaucracy is paralyzed — every policy is blocked by the opposition.', 50, 0.5, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
INSERT INTO scenario_master (scenario_id, title, difficulty, difficulty_label, is_active, objective_desc, context_desc, target_turn, target_stability, initial_state, faction_loyalties, special_conditions) VALUES ('SCENARIO_FALLEN_CROWN', 'The Fallen Crown', 10, 'Insane', False, 'Reclaim stability to 0.8 within 50 turns from a critical starting state. Corruption is locked at 40% and the sanitary crisis is active from Turn 1. One wrong move and it''s Game Over.', 'You inherit a bankrupt kingdom, a starving populace, and territories under constant siege. This is a suicide mission.', 50, 0.8, '{}'::jsonb, '{}'::jsonb, '{}'::jsonb) ON CONFLICT (scenario_id) DO NOTHING;
