INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'Where Does Gold Income Come From', 'elric_gold_income', 'Your Gold grows each turn through taxation of the realm''s population. The amount depends on your current Population size, Prosperity level, and any active Economy Laws. A higher Prosperity grants a larger tax multiplier to your treasury. You may observe your net Gold change in the Resource Bar at the top of the screen — the small value beneath the Gold icon shows your current +X/turn income.', 'economy', 1) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'How to Read the Marketplace Rates', 'elric_marketplace_reading', 'The Marketplace displays exchange rates between Gold and three commodities: Food, Iron, and Wood. Each commodity shows two values — the buy rate (Gold spent to acquire it) and the sell rate (Gold received when selling it). These rates fluctuate each turn based on the kingdom''s economic conditions. Review the current rates before committing to a transaction so you understand precisely how much you will gain or spend.', 'economy', 2) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'How Laws Affect Gold Income', 'elric_laws_gold', 'Certain Laws in the Hall of Laws carry direct effects on your Gold income or expenditure each turn. Economy-category Laws typically improve your Gold per turn, while Laws from other categories may impose a Gold/turn cost as a trade-off. Before enacting any Law, carefully read its description — specifically any line that mentions a Gold cost or bonus expressed as a per-turn value.', 'economy', 3) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'What Is Prosperity and How to Track It', 'elric_prosperity', 'Prosperity measures the economic vitality of your realm on a scale from 0.0 to 1.0, visible in the Resource Bar. It is influenced by active trade Laws, marketplace activity, and certain technologies. A higher Prosperity multiplies your per-turn Gold tax revenue. Should it drop sharply, I would advise checking recently enacted Laws or the current standing of the Merchant Guild — their discontent often precedes an economic downturn.', 'economy', 4) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'How Marketplace Transactions Work', 'elric_marketplace_mechanic', 'To conduct a trade, navigate to the Marketplace, select the desired commodity, and enter the quantity. The system calculates the Gold cost or gain automatically using the current rate. The transaction resolves immediately — resources are credited or debited within the same turn. There are no hidden fees beyond the displayed rate. What you see is precisely what you receive, my liege.', 'economy', 5) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('elric', 'Signs of Financial Danger', 'elric_financial_danger', 'Your treasury is under strain when Gold approaches zero or your net per-turn income turns negative. Watch for these indicators: the Gold +X/turn value in the Resource Bar turning red, warning notifications appearing before you End Turn, and Stability beginning to erode as active Laws can no longer be funded. Visit the Hall of Laws to identify which active Laws carry the heaviest Gold/turn costs — those are your first candidates for review.', 'economy', 6) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'How the Army System Works', 'valerius_army_system', 'Your Army represents the total military strength of the realm, displayed as a numerical value in the Resource Bar. This figure reflects the number of active soldiers under your command. A strong Army reinforces Stability and is a prerequisite for certain military Laws. Without sufficient forces, your kingdom becomes vulnerable to external threats that emerge through random events. Do not let your guard down, Commander.', 'military', 1) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'How to Recruit Army and Its Costs', 'valerius_army_recruitment', 'Army strength is increased by activating military Laws in the Hall of Laws — such as Compulsory Military Service — which add soldiers each turn. Most military Laws carry a cost: Gold per turn, a Stability penalty, or both. Before activating any military Law, review its effect description carefully. It will state explicitly how many units are added and what resources are consumed to sustain them.', 'military', 2) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'Where to Monitor Military Strength', 'valerius_military_status', 'Your current Army size is always visible in the Resource Bar at the top — look for the sword icon. For a full breakdown, visit the War Room. It displays your active Army count, all currently enacted military Laws, and the net change in Army strength per turn. Consider this your command center — consult it regularly to ensure the realm''s defenses remain sound.', 'military', 3) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'What Happens When the Army Grows Too Large', 'valerius_army_drain', 'Sustaining a large Army is not without burden. Each active military Law that contributes soldiers also carries ongoing costs — Gold per turn, Stability penalties, or resource consumption. Stacking too many military Laws simultaneously can strain both your treasury and your realm''s morale. Review your active Laws in the Hall of Laws and monitor the cumulative Gold/turn expenditure to ensure you are not overextending your forces.', 'military', 4) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'How Military Laws Affect the Army', 'valerius_military_laws', 'Laws under the Military category in the Hall of Laws directly modify your Army strength each turn. Each Law carries distinct effects — some add raw troop numbers, others improve defensive efficiency, and some generate bonus loyalty with the Military Order faction. Activate military Laws incrementally and observe their impact on your resources before committing to additional ones. A disciplined approach prevents costly overreach.', 'military', 5) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('valerius', 'Threat Indicators in the War Room', 'valerius_war_room_indicators', 'The War Room gives you a full picture of your military situation — active Army count, running military Laws, and per-turn Army changes. External threats such as border skirmishes will surface as event popups requiring your immediate decision. These events are time-sensitive: unresolved threats can lead to Army losses or Stability penalties. Make it a habit to check the War Room every few turns. Complacency costs lives, my liege.', 'military', 6) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'What Is Faction Loyalty and Where to Find It', 'seraphina_loyalty_basics', 'Faction Loyalty reflects how devoted each of the five great factions is to your crown, measured on a scale from 0.0 to 1.0. The five factions are: the Merchant Guild, Military Order, Common Folk, Arcane Circle, and Agricultural Union. You may view each faction''s current Loyalty, their per-turn trend, and their Council seat count on the Diplomacy page. I recommend visiting it at the start of each turn to stay informed.', 'diplomacy', 1) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'What Causes Loyalty to Rise or Fall', 'seraphina_loyalty_factors', 'Faction Loyalty shifts in response to several forces: the Laws you enact or repeal (each carries faction stance data that favors some factions and alienates others), your choices during events, Council outcomes, and the resource conditions relevant to each faction''s domain. The Agricultural Union, for instance, is highly sensitive to Food levels, while the Merchant Guild responds strongly to trade-related Laws. Understanding these relationships is the foundation of lasting alliances.', 'diplomacy', 2) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'How the Council Works', 'seraphina_council_mechanic', 'The Council is the legislative body of your realm, composed of the five factions each holding a number of seats proportional to their influence. Each faction is represented by a Spokesperson who may bring requests, demands, or grievances before the throne. The Council''s composition affects the flow of Political Points and the ease with which new Laws may be passed. A fractured Council makes governance difficult — a united one amplifies your authority. Full details are visible on the Diplomacy page.', 'diplomacy', 3) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'What Are Political Points and Where They Come From', 'seraphina_political_points', 'Political Points, or PP, are the currency of governance — required to enact higher-tier Laws that carry greater consequences for the realm. PP accumulates each turn based on your Base PP value, reduced by a penalty if your total buildings exceed the Administrative Strain threshold. Your current PP and net change per turn are displayed in the Resource Bar. PP does not carry over beyond its cap, so spend it thoughtfully before it is wasted.', 'diplomacy', 4) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'How Laws Shape Faction Relations', 'seraphina_laws_factions', 'Every Law in the Hall of Laws carries faction stance data — it defines which factions will grow more loyal and which will feel slighted when that Law is enacted. Some Laws benefit one faction greatly while quietly eroding another''s trust. Before activating any Law, read its faction stance information carefully. Governance is as much about managing perception as it is about managing resources, my liege.', 'diplomacy', 5) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('seraphina', 'Where to See All Factions at a Glance', 'seraphina_faction_overview', 'The Diplomacy page serves as your complete overview of all five factions — their Loyalty scores, Influence ratings, and Council seat counts displayed side by side. It also surfaces any active Faction Quests: special requests from individual factions that, if completed within the stated deadline, reward increased Loyalty and Influence. Neglecting these quests risks the opposite — a decline in standing that may take many turns to recover.', 'diplomacy', 6) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'What Is Mana and Where It Comes From', 'silas_mana_basics', 'Mana is the arcane energy that powers all research within the Tech Lab. It is represented as a value between 0.0 and 1.0 in the Resource Bar. Its primary sources are active Arcane-category Laws, certain buildings such as the Temple and University, and technologies that have already been researched. Without sufficient Mana reserves, higher-tier research cannot be initiated. Tend to your arcane infrastructure, and knowledge will follow.', 'tech', 1) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'How to Read the Technology Tree', 'silas_tech_tree', 'The Technology Tree organizes all available research into tiers. Tier 1 technologies are available from the start, while higher tiers require specific prerequisites — earlier technologies that must be completed before access is granted. Each entry shows its Gold and Mana cost, the number of turns required to research it, and the permanent effect it grants upon completion. Status indicators show whether a technology is available, in progress, or already researched.', 'tech', 2) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'How Buildings Are Constructed and How Long They Take', 'silas_buildings_construction', 'Buildings are commissioned through the Infrastructure page by paying the required Gold and Food for the chosen building type. Once construction begins, a set number of turns must pass before the building is completed and its effects become active. You can track ongoing construction in the Infrastructure page — buildings under construction display an In Construction status alongside the remaining turns until completion.', 'tech', 3) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'Effects Granted When a Technology Is Completed', 'silas_tech_effects', 'Upon completing a research project, its effects are applied permanently to the realm — this may include increased per-turn resource production, expanded population capacity, reduced construction costs, or other kingdom-wide bonuses. The full list of effects is visible in each technology''s description before research begins. Once completed, the impact will be reflected in your Resource Bar from the very next turn onward.', 'tech', 4) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'Where to View All Active Buildings', 'silas_buildings_overview', 'The Infrastructure page displays every building you have constructed, along with its current level and operational status. Each building type has a maximum level — upgrading increases its effect at an additional cost. Take note of your total building count here, as it directly relates to Administrative Strain: once the number of buildings surpasses the Strain Threshold, your Political Points per turn will begin to decrease as a governance penalty.', 'tech', 5) ON CONFLICT (topic_key) DO NOTHING;
INSERT INTO advisory_guide (advisor_key, topic_title, topic_key, content, category, "order") VALUES ('silas', 'How Infrastructure Affects Your Resources', 'silas_infrastructure_impact', 'Different building categories contribute to different aspects of the realm. Farms increase Food output, Mines increase Iron, Lumber Mills increase Wood, while population-category buildings expand your citizen capacity and improve Stability. Effects are cumulative — more buildings of the same type, and higher upgrade levels, compound the benefit. Detailed per-level stat breakdowns are accessible through the Building Stats section of the Infrastructure page.', 'tech', 6) ON CONFLICT (topic_key) DO NOTHING;
